import json
import logging
import os
import tempfile
from pathlib import PurePath
from typing import Set, List, Optional, Iterable, Tuple

import numpy as np
from geosat.cloud import PointCloud
from geosat.psanp.abstractions.bundle_classifier import get_bundle_classifier_from_name
from geosat.psanp.abstractions.bundler import Bundle
from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from geosat.tools.urlprotocol import UrlReader, UrlProtocols

from psanp.classifiers.tensorflow.rosaline_classifier.losses import (
    LossWeightsDictFromSettings,
    LossDictFromSettings,
    MetricsDictFromSettings,
)
from psanp.classifiers.tensorflow.rosaline_classifier.network import Network
from psanp.classifiers.tensorflow.rosaline_classifier.pc_loader import (
    PcLoader,
    RosalineNoDataError,
)
from psanp.classifiers.tensorflow.rosaline_classifier.settings import Settings

ROSALINE_TRAJECTORY_BASENAME = "ROSALINE_trajectory.rostrj"
logger = logging.getLogger(__name__)


class RosalineClassifier(Classifier):
    """A classifier to detect and classify road markings from a point cloud
    where the ground has already been classified. This classifier requires a
    trajectory in the same folder as the input point clouds. The trajectory
    must be in a file named ``ROSALINE_trajectory.rostrj``, which must be
    delimited by ";", have a header and 3 columns:

        - ``x``: the easting in a cartesian coordinates system
        - ``y``: the northing in a cartesian coordinates system
        - ``heading``: the orientation in degrees of the vehicle
          (0° if the vehicle is facing east, -90° if the vehicle is facing north)
    """

    def __init__(
        self,
        intensity_min_bound: Optional[int] = None,
        intensity_max_bound: Optional[int] = None,
        export_rasters: bool = False,
        epsg: Optional[int] = None,
        stage_name: Optional[str] = None,
    ):
        super().__init__(stage_name)
        self.intensity_min_bound = intensity_min_bound
        self.intensity_max_bound = intensity_max_bound
        self.export_rasters = export_rasters
        self.epsg = epsg
        if stage_name is None:
            self.config = Settings()
            self.model = Network(self.config)
        else:
            bundle: Bundle = get_bundle_classifier_from_name(self.stage_name)
            self._import_training_data(**bundle["database"])
        self.model.compile(
            "Adam",
            loss=LossDictFromSettings(self.config),
            loss_weights=LossWeightsDictFromSettings(self.config),
            metrics=MetricsDictFromSettings(self.config),
        )

    def _import_training_data(self, model_weights: bytes, config_file: bytes) -> None:
        self.config = Settings(**json.loads(config_file.decode("ascii")))
        self.model = Network(self.config)

        # write model_weight tmp file
        file_object, path = tempfile.mkstemp()
        with open(file_object, "wb") as tmp:
            tmp.write(model_weights)

        self.model.load_weights(path)

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option(
                "intensity_min_bound",
                type_cast=int,
                required=False,
                description="Min intensity bound",
            ),
            Option(
                "intensity_max_bound",
                type_cast=int,
                required=False,
                description="Max intensity bound",
            ),
            Option(
                "export_rasters",
                type_cast=bool,
                required=False,
                description="Export ROSALINE rasters (intensity, elevation min/max, "
                "classification, segmentation and lanes",
            ),
            Option(
                "epsg",
                type_cast=int,
                required=False,
                description="EPSG of the rasters",
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if not cloud:
            return (cloud,)
        # Read trajectory from the directory of the pointcloud
        urlp = UrlProtocols()
        origin_path = urlp.extract_path(os.path.dirname(pipeline_metadata.source))
        rostrj_path = origin_path.with_name(ROSALINE_TRAJECTORY_BASENAME)
        rostrj_url = urlp.integrate_path(
            os.path.dirname(pipeline_metadata.source), rostrj_path
        )
        with UrlReader(rostrj_url, urlp) as file_o:
            trajectory = np.loadtxt(file_o, delimiter=";", skiprows=1)

        if "segmentation" in self.config.data.output_channels_list:
            cloud.add_new_field("segmentation", dtype=np.float64)
        if "linear" in self.config.data.output_channels_list:
            cloud.add_new_field("linear", dtype=np.float64)

        intensity_bounds: Optional[Tuple[int, int]] = (
            None
            if self.intensity_min_bound is None or self.intensity_max_bound is None
            else (self.intensity_min_bound, self.intensity_max_bound)
        )
        try:
            # Preprocess pointcloud with trajectory
            dataset = PcLoader(
                cloud,
                trajectory,
                self.config,
                override_intensity_bounds=intensity_bounds,
                ground_class=pipeline_metadata.classification_codes["ground"],
            )
        except RosalineNoDataError as exception:
            logger.warning(exception)
            return (cloud,)

        # Process batches
        for batch in dataset:
            predictions = self.model.predict_on_batch(batch)
            dataset.project_batch(predictions)

        # Reproject rasters on pointcloud
        dataset.reproject_raster()

        # Export processed data
        mapping = np.array(
            [
                pipeline_metadata.classification_codes[class_name]
                for class_name in self.config.data.class_names
            ]
        )

        # Export rasters if needed
        if self.export_rasters:
            url = cloud.metadata["filepath"]
            stem_url = urlp.integrate_path(
                os.path.dirname(url), PurePath(urlp.extract_path(url).stem)
            )
            dataset.save_raster(stem_url, self.epsg)

        # Remap data to original pointcloud
        mask = cloud.classification == pipeline_metadata.classification_codes["ground"]

        if "semantic" in self.config.data.output_channels_list:
            cloud.classification[mask] = mapping[dataset.laz.classification]
        if "segmentation" in self.config.data.output_channels_list:
            cloud.segmentation[mask] = dataset.laz.segmentation
        if "linear" in self.config.data.output_channels_list:
            cloud.linear[mask] = dataset.laz.linear

        return (cloud,)

    def input_classes(self) -> Set[str]:
        return {"ground"}

    def output_classes(self) -> Set[str]:
        return set(self.config.data.class_names)
